import {
  createContext,
  type CSSProperties,
  type FormEvent,
  forwardRef,
  type ReactNode,
  useCallback,
  useImperativeHandle,
  useMemo,
  useRef,
} from 'react';
import { cls, useNamespace } from '../../utils';
import {
  type ComponentSize,
  ConfigProvider,
  useDisabled,
  useSize,
} from '../../config-provider';

export type FormLabelPosition = 'left' | 'right' | 'top';
export type FormRequireAsteriskPosition = 'left' | 'right';

/** A single validation rule, mirroring the pragmatic subset of Element Plus rules. */
export interface FormRule {
  /** The value must not be empty. */
  required?: boolean;
  /** Message shown when the rule fails; otherwise a sensible default is used. */
  message?: string;
  /** Minimum string length / array length / numeric value. */
  min?: number;
  /** Maximum string length / array length / numeric value. */
  max?: number;
  /** Exact string length / array length / numeric value. */
  len?: number;
  /** Regular expression the (string) value must match. */
  pattern?: RegExp;
  /** Built-in type check. */
  type?: 'string' | 'number' | 'email' | 'url' | 'array';
  /** Custom validator; return (or resolve) a message string to fail, or null/void to pass. */
  validator?: (value: unknown) => string | null | void | Promise<string | null | void>;
  /** When this rule should run during interaction-driven validation. */
  trigger?: 'blur' | 'change';
}

/** A registered FormItem, as seen by the Form. */
export interface FormItemEntry {
  prop: string;
  validate: (trigger?: 'blur' | 'change') => Promise<boolean>;
  clear: () => void;
  isRequired: boolean;
}

/** Imperative API exposed through the Form's ref. */
export interface FormInstance {
  /** Validate every registered field; resolves `true` when all pass. */
  validate: () => Promise<boolean>;
  /** Validate a single field by its `prop`. */
  validateField: (prop: string) => Promise<boolean>;
  /**
   * Clear every field's validation state (state + message). Because the Form
   * does not own the controlled `model`, this does not reset field values —
   * the consumer resets its own model. Equivalent to `clearValidate()`.
   */
  resetFields: () => void;
  /** Clear validation messages for the given prop(s), or all when omitted. */
  clearValidate: (props?: string | string[]) => void;
  /** Scroll the given field into view. */
  scrollToField?: (prop: string) => void;
}

export interface FormContextValue {
  model?: Record<string, unknown>;
  rules?: Record<string, FormRule | FormRule[]>;
  labelWidth?: string | number;
  labelPosition: FormLabelPosition;
  labelSuffix?: string;
  size?: ComponentSize;
  disabled: boolean;
  hideRequiredAsterisk: boolean;
  showMessage: boolean;
  registerItem: (entry: FormItemEntry) => void;
  unregisterItem: (prop: string) => void;
}

export const FormContext = createContext<FormContextValue | null>(null);

export interface FormProps {
  /** The values object the consumer keeps; fields read `model[prop]`. */
  model?: Record<string, unknown>;
  /** Rules keyed by `prop`. */
  rules?: Record<string, FormRule | FormRule[]>;
  /** Shared label column width. */
  labelWidth?: string | number;
  /** Label alignment. */
  labelPosition?: FormLabelPosition;
  /** Suffix appended to string labels (e.g. `:`). */
  labelSuffix?: string;
  /** Lay items out in a single row. */
  inline?: boolean;
  /** Size shared by descendant form items. */
  size?: ComponentSize;
  /** Disable every descendant control. */
  disabled?: boolean;
  /** Hide the required asterisk on labels. */
  hideRequiredAsterisk?: boolean;
  /** Side the required asterisk sits on. */
  requireAsteriskPosition?: FormRequireAsteriskPosition;
  /** Whether to render validation messages. */
  showMessage?: boolean;
  /** Scroll to the first errored field after a failed validate. */
  scrollToError?: boolean;
  /** Fired on native form submit. */
  onSubmit?: (event: FormEvent<HTMLFormElement>) => void;
  /** Extra class on the root element. */
  className?: string;
  /** Extra style on the root element. */
  style?: CSSProperties;
  children?: ReactNode;
}

export const Form = forwardRef<FormInstance, FormProps>(function Form(props, ref) {
  const {
    model,
    rules,
    labelWidth,
    labelPosition = 'right',
    labelSuffix,
    inline = false,
    size: sizeProp,
    disabled: disabledProp,
    hideRequiredAsterisk = false,
    requireAsteriskPosition = 'left',
    showMessage = true,
    scrollToError = false,
    onSubmit,
    className,
    style,
    children,
  } = props;

  const ns = useNamespace('form');
  const size = useSize(sizeProp);
  const disabled = useDisabled(disabledProp);

  const items = useRef(new Map<string, FormItemEntry>());

  const registerItem = useCallback((entry: FormItemEntry) => {
    items.current.set(entry.prop, entry);
  }, []);

  const unregisterItem = useCallback((prop: string) => {
    items.current.delete(prop);
  }, []);

  const scrollToField = useCallback((prop: string) => {
    if (typeof document === 'undefined') return;
    const node = document.querySelector(`[data-form-prop="${prop}"]`);
    node?.scrollIntoView({ behavior: 'smooth', block: 'center' });
  }, []);

  const validate = useCallback(async (): Promise<boolean> => {
    const results = await Promise.all(
      [...items.current.values()].map((item) => item.validate()),
    );
    const valid = results.every(Boolean);
    if (!valid && scrollToError) {
      const firstFailed = [...items.current.values()].find((_, index) => !results[index]);
      if (firstFailed) scrollToField(firstFailed.prop);
    }
    return valid;
  }, [scrollToError, scrollToField]);

  const validateField = useCallback(async (prop: string): Promise<boolean> => {
    const item = items.current.get(prop);
    if (!item) return true;
    return item.validate();
  }, []);

  // The Form does not own the controlled `model`, so it cannot restore field
  // values; this clears validation state only (see FormInstance.resetFields).
  const resetFields = useCallback(() => {
    items.current.forEach((item) => item.clear());
  }, []);

  const clearValidate = useCallback((targets?: string | string[]) => {
    if (targets === undefined) {
      items.current.forEach((item) => item.clear());
      return;
    }
    const list = Array.isArray(targets) ? targets : [targets];
    list.forEach((prop) => items.current.get(prop)?.clear());
  }, []);

  useImperativeHandle(
    ref,
    (): FormInstance => ({
      validate,
      validateField,
      resetFields,
      clearValidate,
      scrollToField,
    }),
    [validate, validateField, resetFields, clearValidate, scrollToField],
  );

  const context = useMemo<FormContextValue>(
    () => ({
      model,
      rules,
      labelWidth,
      labelPosition,
      labelSuffix,
      size: sizeProp,
      disabled,
      hideRequiredAsterisk,
      showMessage,
      registerItem,
      unregisterItem,
    }),
    [
      model,
      rules,
      labelWidth,
      labelPosition,
      labelSuffix,
      sizeProp,
      disabled,
      hideRequiredAsterisk,
      showMessage,
      registerItem,
      unregisterItem,
    ],
  );

  const classes = cls(
    ns.b(),
    ns.m(`label-${labelPosition}`),
    size !== 'default' && ns.m(size),
    ns.is('inline', inline),
    ns.is('asterisk-right', requireAsteriskPosition === 'right'),
    className,
  );

  const rootStyle: CSSProperties = { ...style };
  if (labelWidth !== undefined) {
    (rootStyle as Record<string, string>)[ns.cssVar('label-width')] =
      typeof labelWidth === 'number' ? `${labelWidth}px` : labelWidth;
  }

  return (
    <FormContext.Provider value={context}>
      <form className={classes} style={rootStyle} onSubmit={onSubmit}>
        {/*
          Propagate `disabled` through the mechanism descendant controls
          actually read (ConfigProvider -> useDisabled). ConfigProvider composes
          `disabled` with its parent, so a child cannot re-enable itself.
        */}
        <ConfigProvider disabled={disabled}>{children}</ConfigProvider>
      </form>
    </FormContext.Provider>
  );
});

import {
  Children,
  cloneElement,
  type CSSProperties,
  forwardRef,
  isValidElement,
  type ReactElement,
  type ReactNode,
  useContext,
  useEffect,
  useId,
  useMemo,
  useRef,
  useState,
} from 'react';
import { cls, useNamespace } from '../../utils';
import { type ComponentSize } from '../../config-provider';
import { FormContext, type FormRule } from './Form';

export interface FormItemProps {
  /** Label content rendered before the control. */
  label?: ReactNode;
  /** Key in the form `model` this item is bound to. */
  prop?: string;
  /** Force the required asterisk regardless of rules. */
  required?: boolean;
  /** Validation rules for this item; falls back to `form.rules[prop]`. */
  rules?: FormRule | FormRule[];
  /** Manual error message override; takes precedence over validation. */
  error?: string;
  /** Whether to show the validation message. Falls back to the Form. */
  showMessage?: boolean;
  /** Label column width; overrides the Form's `labelWidth`. */
  labelWidth?: string | number;
  /** Native `for` attribute applied to the label. */
  for?: string;
  /** Size; falls back to the Form, then the nearest ConfigProvider. */
  size?: ComponentSize;
  /** Extra class on the root element. */
  className?: string;
  /** Extra style on the root element. */
  style?: CSSProperties;
  children?: ReactNode;
}

const EMAIL_PATTERN = /^[\w.!#$%&'*+/=?^`{|}~-]+@[a-z\d](?:[a-z\d-]{0,61}[a-z\d])?(?:\.[a-z\d](?:[a-z\d-]{0,61}[a-z\d])?)*$/i;
const URL_PATTERN = /^(https?:\/\/)?([\w-]+\.)+[\w-]+(:\d+)?(\/[\w./?%&=#-]*)?$/i;

function isEmpty(value: unknown): boolean {
  if (value === undefined || value === null) return true;
  if (typeof value === 'string') return value.trim().length === 0;
  if (Array.isArray(value)) return value.length === 0;
  return false;
}

function measure(value: unknown): number {
  if (typeof value === 'number') return value;
  if (typeof value === 'string') return value.length;
  if (Array.isArray(value)) return value.length;
  return Number.NaN;
}

function checkType(value: unknown, type: NonNullable<FormRule['type']>): boolean {
  switch (type) {
    case 'string':
      return typeof value === 'string';
    case 'number':
      return typeof value === 'number' && Number.isFinite(value);
    case 'email':
      return typeof value === 'string' && EMAIL_PATTERN.test(value);
    case 'url':
      return typeof value === 'string' && URL_PATTERN.test(value);
    case 'array':
      return Array.isArray(value);
    default:
      return true;
  }
}

/** Validate a single value against a list of rules; resolves the first error message or null. */
export async function runRules(value: unknown, rules: FormRule[]): Promise<string | null> {
  for (const rule of rules) {
    if (rule.required && isEmpty(value)) {
      return rule.message ?? 'This field is required';
    }

    // Skip the remaining checks for empty optional values.
    if (isEmpty(value) && !rule.required) {
      if (rule.validator) {
        const result = await rule.validator(value);
        if (typeof result === 'string') return result;
      }
      continue;
    }

    if (rule.type && !checkType(value, rule.type)) {
      return rule.message ?? `Please enter a valid ${rule.type}`;
    }

    if (rule.len !== undefined) {
      const size = measure(value);
      if (Number.isFinite(size) && size !== rule.len) {
        return rule.message ?? `Length must be exactly ${rule.len}`;
      }
    }

    if (rule.min !== undefined) {
      const size = measure(value);
      if (Number.isFinite(size) && size < rule.min) {
        return rule.message ?? `Must be at least ${rule.min}`;
      }
    }

    if (rule.max !== undefined) {
      const size = measure(value);
      if (Number.isFinite(size) && size > rule.max) {
        return rule.message ?? `Must be at most ${rule.max}`;
      }
    }

    if (rule.pattern && typeof value === 'string' && !rule.pattern.test(value)) {
      return rule.message ?? 'Invalid format';
    }

    if (rule.validator) {
      const result = await rule.validator(value);
      if (typeof result === 'string') return result;
    }
  }

  return null;
}

export const FormItem = forwardRef<HTMLDivElement, FormItemProps>(function FormItem(props, ref) {
  const {
    label,
    prop,
    required,
    rules,
    error,
    showMessage: showMessageProp,
    labelWidth,
    for: htmlFor,
    size: sizeProp,
    className,
    style,
    children,
  } = props;

  const ns = useNamespace('form-item');
  const form = useContext(FormContext);

  const [validateMessage, setValidateMessage] = useState('');
  const [validateState, setValidateState] = useState<'' | 'error' | 'success'>('');

  const size = sizeProp ?? form?.size;
  const showMessage = showMessageProp ?? form?.showMessage ?? true;

  const effectiveRules = useMemo<FormRule[]>(() => {
    const own = rules ? (Array.isArray(rules) ? rules : [rules]) : undefined;
    const fromForm =
      prop && form?.rules?.[prop]
        ? Array.isArray(form.rules[prop])
          ? (form.rules[prop] as FormRule[])
          : [form.rules[prop] as FormRule]
        : undefined;
    const list = own ?? fromForm ?? [];
    if (required && !list.some((rule) => rule.required)) {
      return [{ required: true }, ...list];
    }
    return list;
  }, [rules, prop, form?.rules, required]);

  const isRequired = required || effectiveRules.some((rule) => rule.required);

  // Keep the latest values available to the imperative callbacks without re-registering.
  const stateRef = useRef({ effectiveRules, prop, error });
  stateRef.current = { effectiveRules, prop, error };

  const validate = useMemo(() => {
    return async (trigger?: 'blur' | 'change'): Promise<boolean> => {
      const { effectiveRules: currentRules, prop: currentProp, error: currentError } =
        stateRef.current;

      if (currentError !== undefined && currentError !== '') {
        setValidateState('error');
        setValidateMessage(currentError);
        return false;
      }

      if (!currentProp || currentRules.length === 0) {
        setValidateState('');
        setValidateMessage('');
        return true;
      }

      const applicable = trigger
        ? currentRules.filter((rule) => !rule.trigger || rule.trigger === trigger)
        : currentRules;
      if (applicable.length === 0) return true;

      const value = form?.model?.[currentProp];
      const message = await runRules(value, applicable);
      if (message) {
        setValidateState('error');
        setValidateMessage(message);
        return false;
      }
      setValidateState('success');
      setValidateMessage('');
      return true;
    };
  }, [form]);

  const clear = useMemo(() => {
    return () => {
      setValidateState('');
      setValidateMessage('');
    };
  }, []);

  useEffect(() => {
    if (!prop || !form) return undefined;
    form.registerItem({ prop, validate, clear, isRequired });
    return () => form.unregisterItem(prop);
  }, [prop, form, validate, clear, isRequired]);

  const displayError = error !== undefined && error !== '' ? error : validateMessage;
  const hasError = validateState === 'error' || (error !== undefined && error !== '');

  // Stable ids used to associate the label and error message with the control.
  const generatedId = useId();
  const errorId = `${generatedId}-error`;
  const showError = showMessage && hasError && displayError;

  // Resolve the id the control will actually carry, preferring (in order) the
  // child's own `id`, an explicit `for`, then a generated id. The label's
  // `htmlFor` is wired to the same id so clicking the label focuses the field.
  const childArray = Children.toArray(children);
  const onlyChild = childArray.length === 1 ? childArray[0] : null;
  const singleChild: ReactElement<Record<string, unknown>> | null = isValidElement(onlyChild)
    ? (onlyChild as ReactElement<Record<string, unknown>>)
    : null;
  const childId = singleChild ? (singleChild.props.id as string | undefined) : undefined;
  const controlId = childId ?? htmlFor ?? generatedId;

  // Associate the single element child with this item's label and error so that
  // clicking the label focuses the field and screen readers announce the name
  // and validation message. Falls back to rendering children untouched when
  // there is no single bindable element (e.g. multiple/text children).
  const boundChildren = useMemo<ReactNode>(() => {
    if (!singleChild) return children;
    const childProps = singleChild.props;
    return cloneElement(singleChild, {
      id: controlId,
      'aria-invalid': hasError ? true : (childProps['aria-invalid'] as boolean | undefined),
      'aria-describedby': showError
        ? [childProps['aria-describedby'], errorId].filter(Boolean).join(' ')
        : (childProps['aria-describedby'] as string | undefined),
    });
  }, [singleChild, children, controlId, errorId, hasError, showError]);

  const classes = cls(
    ns.b(),
    size && size !== 'default' && ns.m(size),
    ns.is('required', isRequired),
    ns.is('error', hasError),
    ns.is('success', validateState === 'success'),
    ns.is('no-asterisk', form?.hideRequiredAsterisk ?? false),
    className,
  );

  const labelStyle: CSSProperties = {};
  const width = labelWidth ?? form?.labelWidth;
  if (width !== undefined && form?.labelPosition !== 'top') {
    labelStyle.width = typeof width === 'number' ? `${width}px` : width;
  }

  const labelText =
    typeof label === 'string' && form?.labelSuffix ? `${label}${form.labelSuffix}` : label;

  return (
    <div ref={ref} className={classes} style={style} data-form-prop={prop || undefined}>
      {(label !== undefined && label !== null) || isRequired ? (
        <label className={ns.e('label')} style={labelStyle} htmlFor={controlId}>
          {labelText}
        </label>
      ) : null}
      <div className={ns.e('content')}>
        {boundChildren}
        {showError ? (
          <div className={ns.e('error')} id={errorId} role="alert" aria-live="polite">
            {displayError}
          </div>
        ) : null}
      </div>
    </div>
  );
});

.ec-form {
  --ec-form-label-width: auto;
  --ec-form-label-font-size: var(--ec-font-size-base);
  --ec-form-label-color: var(--ec-text-color-regular);
  --ec-form-item-spacing: 22px;
  --ec-form-error-color: var(--ec-color-danger);

  box-sizing: border-box;
}

/* ---- Form item ---- */
.ec-form-item {
  display: flex;
  box-sizing: border-box;
  margin-bottom: var(--ec-form-item-spacing);
}

.ec-form-item:last-child {
  margin-bottom: 0;
}

.ec-form-item__label {
  display: inline-flex;
  align-items: flex-start;
  box-sizing: border-box;
  flex: 0 0 auto;
  width: var(--ec-form-label-width);
  padding-right: 12px;
  font-size: var(--ec-form-label-font-size);
  font-weight: var(--ec-font-weight-primary);
  line-height: var(--ec-component-size);
  color: var(--ec-form-label-color);
}

.ec-form-item__content {
  display: flex;
  flex: 1;
  flex-direction: column;
  min-width: 0;
}

.ec-form-item__error {
  margin-top: 2px;
  font-size: var(--ec-font-size-small);
  line-height: 1.4;
  color: var(--ec-form-error-color);
}

/* ---- Required asterisk ---- */
.ec-form-item.is-required:not(.is-no-asterisk) .ec-form-item__label::before {
  content: '*';
  margin-right: 4px;
  color: var(--ec-form-error-color);
}

.ec-form.is-asterisk-right
  .ec-form-item.is-required:not(.is-no-asterisk)
  .ec-form-item__label::before {
  content: '';
  margin-right: 0;
}

.ec-form.is-asterisk-right
  .ec-form-item.is-required:not(.is-no-asterisk)
  .ec-form-item__label::after {
  content: '*';
  margin-left: 4px;
  color: var(--ec-form-error-color);
}

/* ---- Label position ---- */
.ec-form--label-left .ec-form-item__label {
  justify-content: flex-start;
  text-align: left;
}

.ec-form--label-right .ec-form-item__label {
  justify-content: flex-end;
  text-align: right;
}

.ec-form--label-top .ec-form-item {
  display: block;
}

.ec-form--label-top .ec-form-item__label {
  width: auto;
  padding: 0 0 4px;
  line-height: 1.4;
}

/* ---- Inline ---- */
.ec-form.is-inline {
  display: flex;
  flex-wrap: wrap;
  align-items: flex-start;
}

.ec-form.is-inline .ec-form-item {
  margin-right: var(--ec-form-item-spacing);
  margin-bottom: 0;
}

.ec-form.is-inline .ec-form-item__content {
  flex: 0 0 auto;
}

/* ---- Validation state ---- */
.ec-form-item.is-error .ec-input .ec-input__wrapper {
  box-shadow: 0 0 0 1px var(--ec-color-danger) inset;
}

/* ---- Sizes ---- */
.ec-form-item--large .ec-form-item__label {
  line-height: var(--ec-component-size-large);
}

.ec-form-item--small .ec-form-item__label {
  font-size: var(--ec-font-size-small);
  line-height: var(--ec-component-size-small);
}
